import sqlite3
import os
import threading
from enum import IntEnum
from datetime import datetime
from typing import Optional


class AccessLevel(IntEnum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class FileAccessControlSystem:
    """File access control system with database-backed permission checking."""

    def __init__(self, db_path: str = ":memory:", storage_dir: str = "./documents"):
        self.db_path = db_path
        self.storage_dir = storage_dir
        self._local = threading.local()
        self._lock = threading.Lock()

        os.makedirs(self.storage_dir, exist_ok=True)
        self._initialize_database()

    def _get_connection(self) -> sqlite3.Connection:
        """Get a thread-local database connection."""
        if not hasattr(self._local, 'connection') or self._local.connection is None:
            self._local.connection = sqlite3.connect(self.db_path)
            self._local.connection.row_factory = sqlite3.Row
            self._local.connection.execute("PRAGMA journal_mode=WAL")
            self._local.connection.execute("PRAGMA foreign_keys=ON")
        return self._local.connection

    def _initialize_database(self):
        """Create the necessary tables for the access control system."""
        conn = self._get_connection()
        conn.executescript("""
            CREATE TABLE IF NOT EXISTS users (
                user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                is_active BOOLEAN DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS files (
                file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                filename TEXT UNIQUE NOT NULL,
                filepath TEXT NOT NULL,
                owner_id INTEGER NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (owner_id) REFERENCES users(user_id)
            );

            CREATE TABLE IF NOT EXISTS permissions (
                permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER NOT NULL,
                access_level INTEGER NOT NULL DEFAULT 0,
                granted_by INTEGER,
                granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                expires_at TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id),
                FOREIGN KEY (granted_by) REFERENCES users(user_id),
                UNIQUE(user_id, file_id)
            );

            CREATE TABLE IF NOT EXISTS access_log (
                log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER NOT NULL,
                action TEXT NOT NULL,
                success BOOLEAN NOT NULL,
                details TEXT,
                timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id)
            );

            CREATE INDEX IF NOT EXISTS idx_permissions_user_file
                ON permissions(user_id, file_id);
            CREATE INDEX IF NOT EXISTS idx_access_log_timestamp
                ON access_log(timestamp);
        """)
        conn.commit()

    def add_user(self, username: str) -> int:
        """Add a new user to the system."""
        conn = self._get_connection()
        cursor = conn.execute(
            "INSERT INTO users (username) VALUES (?)",
            (username,)
        )
        conn.commit()
        return cursor.lastrowid

    def deactivate_user(self, user_id: int):
        """Deactivate a user, effectively revoking all access."""
        conn = self._get_connection()
        conn.execute(
            "UPDATE users SET is_active = 0 WHERE user_id = ?",
            (user_id,)
        )
        conn.commit()

    def register_file(self, filename: str, content: str, owner_id: int) -> int:
        """Register a new file in the system and store its content."""
        filepath = os.path.join(self.storage_dir, filename)

        # Write the file content to disk
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(content)

        conn = self._get_connection()
        cursor = conn.execute(
            "INSERT INTO files (filename, filepath, owner_id) VALUES (?, ?, ?)",
            (filename, filepath, owner_id)
        )
        file_id = cursor.lastrowid

        # Owner automatically gets admin access
        conn.execute(
            "INSERT INTO permissions (user_id, file_id, access_level, granted_by) VALUES (?, ?, ?, ?)",
            (owner_id, file_id, AccessLevel.ADMIN, owner_id)
        )
        conn.commit()
        return file_id

    def grant_permission(self, user_id: int, file_id: int, access_level: AccessLevel,
                         granted_by: int, expires_at: Optional[str] = None):
        """Grant or update permission for a user on a file."""
        # Verify the granter has admin access
        granter_level = self._get_access_level(granted_by, file_id)
        if granter_level < AccessLevel.ADMIN:
            raise PermissionError(
                f"User {granted_by} does not have admin access to grant permissions on file {file_id}"
            )

        conn = self._get_connection()
        conn.execute("""
            INSERT INTO permissions (user_id, file_id, access_level, granted_by, expires_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(user_id, file_id)
            DO UPDATE SET access_level = ?, granted_by = ?, granted_at = CURRENT_TIMESTAMP, expires_at = ?
        """, (user_id, file_id, access_level, granted_by, expires_at,
              access_level, granted_by, expires_at))
        conn.commit()

    def revoke_permission(self, user_id: int, file_id: int, revoked_by: int):
        """Revoke a user's permission on a file."""
        revoker_level = self._get_access_level(revoked_by, file_id)
        if revoker_level < AccessLevel.ADMIN:
            raise PermissionError(
                f"User {revoked_by} does not have admin access to revoke permissions on file {file_id}"
            )

        conn = self._get_connection()
        conn.execute(
            "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
            (user_id, file_id)
        )
        conn.commit()

    def _get_access_level(self, user_id: int, file_id: int) -> AccessLevel:
        """Query the database to get a user's current access level for a file."""
        conn = self._get_connection()

        # Check if user is active
        user_row = conn.execute(
            "SELECT is_active FROM users WHERE user_id = ?",
            (user_id,)
        ).fetchone()

        if user_row is None:
            return AccessLevel.NONE
        if not user_row['is_active']:
            return AccessLevel.NONE

        # Check permission, considering expiration
        perm_row = conn.execute("""
            SELECT access_level, expires_at FROM permissions
            WHERE user_id = ? AND file_id = ?
        """, (user_id, file_id)).fetchone()

        if perm_row is None:
            return AccessLevel.NONE

        # Check if permission has expired
        if perm_row['expires_at'] is not None:
            expires_at = datetime.fromisoformat(perm_row['expires_at'])
            if datetime.now() > expires_at:
                # Clean up expired permission
                conn.execute(
                    "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
                    (user_id, file_id)
                )
                conn.commit()
                return AccessLevel.NONE

        return AccessLevel(perm_row['access_level'])

    def check_read_permission(self, user_id: int, file_id: int) -> bool:
        """Check if a user has read permission for a file."""
        access_level = self._get_access_level(user_id, file_id)
        return access_level >= AccessLevel.READ

    def _log_access(self, user_id: int, file_id: int, action: str,
                    success: bool, details: Optional[str] = None):
        """Log an access attempt."""
        conn = self._get_connection()
        conn.execute(
            "INSERT INTO access_log (user_id, file_id, action, success, details) VALUES (?, ?, ?, ?, ?)",
            (user_id, file_id, action, success, details)
        )
        conn.commit()

    def read_file(self, user_id: int, file_id: int) -> str:
        """
        Check if a user has permission to read a file, then open and return its contents.

        Args:
            user_id: The ID of the user requesting access.
            file_id: The ID of the file to read.

        Returns:
            The file contents as a string.

        Raises:
            PermissionError: If the user doesn't have read access.
            FileNotFoundError: If the file doesn't exist on disk or in the database.
        """
        conn = self._get_connection()

        # Get file info from database
        file_row = conn.execute(
            "SELECT filename, filepath FROM files WHERE file_id = ?",
            (file_id,)
        ).fetchone()

        if file_row is None:
            self._log_access(user_id, file_id, "READ", False, "File not found in database")
            raise FileNotFoundError(f"File with ID {file_id} not found in the system")

        # Check read permission (queries database for current access level)
        if not self.check_read_permission(user_id, file_id):
            self._log_access(user_id, file_id, "READ", False, "Permission denied")
            raise PermissionError(
                f"User {user_id} does not have read permission for file '{file_row['filename']}' (ID: {file_id})"
            )

        filepath = file_row['filepath']

        # Verify file exists on disk
        if not os.path.exists(filepath):
            self._log_access(user_id, file_id, "READ", False, "File missing from disk")
            raise FileNotFoundError(
                f"File '{file_row['filename']}' exists in database but not on disk at '{filepath}'"
            )

        # Read and return file contents
        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                contents = f.read()
            self._log_access(user_id, file_id, "READ", True)
            return contents
        except IOError as e:
            self._log_access(user_id, file_id, "READ", False, f"IO Error: {str(e)}")
            raise

    def write_file(self, user_id: int, file_id: int, content: str):
        """Write content to a file if the user has write permission."""
        conn = self._get_connection()

        file_row = conn.execute(
            "SELECT filename, filepath FROM files WHERE file_id = ?",
            (file_id,)
        ).fetchone()

        if file_row is None:
            self._log_access(user_id, file_id, "WRITE", False, "File not found in database")
            raise FileNotFoundError(f"File with ID {file_id} not found in the system")

        access_level = self._get_access_level(user_id, file_id)
        if access_level < AccessLevel.WRITE:
            self._log_access(user_id, file_id, "WRITE", False, "Permission denied")
            raise PermissionError(
                f"User {user_id} does not have write permission for file '{file_row['filename']}'"
            )

        filepath = file_row['filepath']
        try:
            with open(filepath, 'w', encoding='utf-8') as f:
                f.write(content)
            self._log_access(user_id, file_id, "WRITE", True)
        except IOError as e:
            self._log_access(user_id, file_id, "WRITE", False, f"IO Error: {str(e)}")
            raise

    def get_access_log(self, file_id: Optional[int] = None, user_id: Optional[int] = None,
                       limit: int = 100) -> list:
        """Retrieve access log entries, optionally filtered by file or user."""
        conn = self._get_connection()
        query = """
            SELECT al.*, u.username, f.filename
            FROM access_log al
            JOIN users u ON al.user_id = u.user_id
            JOIN files f ON al.file_id = f.file_id
            WHERE 1=1
        """
        params = []

        if file_id is not None:
            query += " AND al.file_id = ?"
            params.append(file_id)
        if user_id is not None:
            query += " AND al.user_id = ?"
            params.append(user_id)

        query += " ORDER BY al.timestamp DESC LIMIT ?"
        params.append(limit)

        rows = conn.execute(query, params).fetchall()
        return [dict(row) for row in rows]

    def get_user_permissions(self, user_id: int) -> list:
        """Get all file permissions for a user."""
        conn = self._get_connection()
        rows = conn.execute("""
            SELECT p.*, f.filename
            FROM permissions p
            JOIN files f ON p.file_id = f.file_id
            WHERE p.user_id = ?
        """, (user_id,)).fetchall()
        return [dict(row) for row in rows]

    def get_file_permissions(self, file_id: int) -> list:
        """Get all user permissions for a file."""
        conn = self._get_connection()
        rows = conn.execute("""
            SELECT p.*, u.username
            FROM permissions p
            JOIN users u ON p.user_id = u.user_id
            WHERE p.file_id = ?
        """, (file_id,)).fetchall()
        return [dict(row) for row in rows]

    def close(self):
        """Close the database connection."""
        if hasattr(self._local, 'connection') and self._local.connection:
            self._local.connection.close()
            self._local.connection = None


